class Solution {
public:
    int subarrayGCD(vector<int>& nums, int k) {
        int count = 0;
        for (int i = 0; i < nums.size(); i++) {
            int gcd = 0;
            for (int j = i; j < nums.size(); j++) {
                if (gcd == 0) {
                    gcd = nums[j];
                } else {
                    gcd = __gcd(gcd, nums[j]);
                }
                if (gcd == k) {
                    count++;
                }
            }
        }
        return count;
    }
};

